const t={klipperscreenStudio:{intro:{t:0,b:{t:2,i:[{t:3}],s:"安全地编辑打印机的 KlipperScreen 触摸屏配置，然后重启 KlipperScreen 以应用。每次保存前都会先备份。"}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"工作原理"}},body:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf 控制连接到打印机的触摸屏——主题、语言、菜单和显示选项。此编辑器通过与配置编辑器相同的安全路径读写该文件。"}},step1:{t:0,b:{t:2,i:[{t:3}],s:"在下方编辑配置文本（或保持不变）。"}},step2:{t:0,b:{t:2,i:[{t:3}],s:"保存——文件会先备份，且在打印机忙碌时拒绝保存。"}},step3:{t:0,b:{t:2,i:[{t:3}],s:"重启 KlipperScreen 以在实体屏幕上应用更改。"}},lfNote:{t:0,b:{t:2,i:[{t:3}],s:"行使用 UNIX (LF) 换行符，保存时自动强制。"}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"术语表"}},body:{t:0,b:{t:2,i:[{t:3}],s:"这里使用的 KlipperScreen 术语的简明定义。"}}},config:{title:{t:0,b:{t:2,i:[{t:3}],s:"“配置”标签是什么？"}},body:{t:0,b:{t:2,i:[{t:3}],s:"原始的 KlipperScreen.conf。可手动编辑任意设置；保存时会先备份文件，在打印机忙碌时拒绝保存，并在文件自加载以来已在屏幕上更改时发出警告。大多数人会改用“设置 / 菜单 / 主题”标签。"}}},settings:{title:{t:0,b:{t:2,i:[{t:3}],s:"“设置”标签是什么？"}},body:{t:0,b:{t:2,i:[{t:3}],s:"以表单形式提供最常用的 [main] 选项——主题、语言、息屏、字体大小及各项开关。从实时配置预填；只有你更改的选项才会写入。重启后生效。"}}},menus:{title:{t:0,b:{t:2,i:[{t:3}],s:"“菜单”标签是什么？"}},body:{t:0,b:{t:2,i:[{t:3}],s:"设计触摸屏的按钮网格。每棵树（__main 是主屏网格，__print 是打印屏）都列出其按钮；可添加、重命名、重新排序和嵌套它们，并设置每个按钮去打开子菜单、打开内置屏幕或运行 G-code。"}}},themes:{title:{t:0,b:{t:2,i:[{t:3}],s:"“主题”标签是什么？"}},body:{t:0,b:{t:2,i:[{t:3}],s:"构建一个 KlipperScreen 主题：为每个调色板色键选择颜色并设置圆角半径，查看实时预览，然后创建并应用到屏幕。预览仅为近似——实际屏幕由 GTK 渲染。"}}},kiosk:{title:{t:0,b:{t:2,i:[{t:3}],s:"“自助屏”标签是什么？"}},body:{t:0,b:{t:2,i:[{t:3}],s:"把 FilaMind Flow 本身以全屏浏览器形式显示在触摸屏上——完全掌控屏幕显示内容。它与 KlipperScreen 是可逆互换的（默认临时；重启会恢复 KlipperScreen）。需要在打印机主机上执行一次安装程序。"}}}},glossary:{klipperScreen:{term:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen"}},def:{t:0,b:{t:2,i:[{t:3}],s:"在连接到打印机的小型显示屏上运行的触摸屏界面——与此网页面板相互独立。"}}},theme:{term:{t:0,b:{t:2,i:[{t:3}],s:"主题"}},def:{t:0,b:{t:2,i:[{t:3}],s:"一种 KlipperScreen 外观——颜色、图标和圆角半径。存放在主机上的 styles/<name> 文件夹中；仅为外观，不能改变布局。"}}},menu:{term:{t:0,b:{t:2,i:[{t:3}],s:"菜单（__main / __print）"}},def:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen 显示的按钮网格。__main 是主屏，__print 是打印时显示的屏幕，__splashscreen 是启动屏幕。"}}},panel:{term:{t:0,b:{t:2,i:[{t:3}],s:"屏幕"}},def:{t:0,b:{t:2,i:[{t:3}],s:"按钮可打开的 KlipperScreen 内置屏幕（移动、温度、挤出、热床网格……）。它们的内部内容由 KlipperScreen 固定。"}}},autoBlock:{term:{t:0,b:{t:2,i:[{t:3}],s:"自动生成块（#~#）"}},def:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen 在配置文件底部、#~# 标记之后为自身写入的区段。FilaMind 从不编辑它——只编辑它上方的设置。"}}},kiosk:{term:{t:0,b:{t:2,i:[{t:3}],s:"自助屏"}},def:{t:0,b:{t:2,i:[{t:3}],s:"在触摸屏上运行全屏浏览器而非 KlipperScreen，使屏幕显示 FilaMind Flow。完全可逆。"}}}}},status:{checking:{t:0,b:{t:2,i:[{t:3}],s:"正在检测 KlipperScreen…"}},absent:{t:0,b:{t:2,i:[{t:3}],s:"未在此打印机上检测到 KlipperScreen（没有 KlipperScreen.conf，且 Moonraker 未报告）。请安装 KlipperScreen 以使用此工具。"}},present:{t:0,b:{t:2,i:[{t:3}],s:"已检测到 KlipperScreen"}},theme:{t:0,b:{t:2,i:[{t:3}],s:"主题"}},language:{t:0,b:{t:2,i:[{t:3}],s:"语言"}},notRestartable:{t:0,b:{t:2,i:[{t:3}],s:"Moonraker 无法自动重启 KlipperScreen——保存后请手动重启。"}}},editor:{loading:{t:0,b:{t:2,i:[{t:3}],s:"正在读取 KlipperScreen.conf…"}},reload:{t:0,b:{t:2,i:[{t:3}],s:"重新加载"}},save:{t:0,b:{t:2,i:[{t:3}],s:"保存配置"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"保存中…"}},saved:{t:0,b:{t:2,i:[{t:3}],s:"已保存（已备份）"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"未保存的更改"}}},save:{busy:{t:0,b:{t:2,i:[{t:3}],s:"打印机忙碌时被拒绝——空闲时再试。"}},stale:{t:0,b:{t:2,i:[{t:3}],s:"自加载以来 KlipperScreen.conf 在磁盘上已更改（可能在屏幕上编辑过）。保存前请重新加载，以免覆盖该更改。"}}},view:{config:{t:0,b:{t:2,i:[{t:3}],s:"配置"}},settings:{t:0,b:{t:2,i:[{t:3}],s:"设置"}},menus:{t:0,b:{t:2,i:[{t:3}],s:"菜单"}},themes:{t:0,b:{t:2,i:[{t:3}],s:"主题"}},kiosk:{t:0,b:{t:2,i:[{t:3}],s:"自助屏"}}},settings:{loading:{t:0,b:{t:2,i:[{t:3}],s:"正在加载设置…"}},intro:{t:0,b:{t:2,i:[{t:3}],s:"以表单形式提供最常用的 KlipperScreen 显示选项。只写入你更改的项——其余保持原值。重启后生效。"}},onlyChanged:{t:0,b:{t:2,i:[{t:3}],s:"只有你在此更改的设置才会写入 KlipperScreen.conf。"}},save:{t:0,b:{t:2,i:[{t:3}],s:"保存设置"}},savedRestart:{t:0,b:{t:2,i:[{t:3}],s:"已保存——重启 KlipperScreen 以生效。"}},unset:{t:0,b:{t:2,i:[{t:3}],s:"保持未设置（默认）"}},never:{t:0,b:{t:2,i:[{t:3}],s:"从不（常亮）"}},fontSize:{small:{t:0,b:{t:2,i:[{t:3}],s:"小"}},medium:{t:0,b:{t:2,i:[{t:3}],s:"中"}},large:{t:0,b:{t:2,i:[{t:3}],s:"大"}},max:{t:0,b:{t:2,i:[{t:3}],s:"最大"}}},label:{theme:{t:0,b:{t:2,i:[{t:3}],s:"主题"}},language:{t:0,b:{t:2,i:[{t:3}],s:"语言"}},screen_blanking:{t:0,b:{t:2,i:[{t:3}],s:"息屏延时"}},font_size:{t:0,b:{t:2,i:[{t:3}],s:"字体大小"}},"24htime":{t:0,b:{t:2,i:[{t:3}],s:"24 小时制"}},use_dpms:{t:0,b:{t:2,i:[{t:3}],s:"使用 DPMS 息屏"}},show_cursor:{t:0,b:{t:2,i:[{t:3}],s:"显示鼠标指针"}},confirm_estop:{t:0,b:{t:2,i:[{t:3}],s:"急停前确认"}},show_heater_power:{t:0,b:{t:2,i:[{t:3}],s:"显示加热器功率 %"}},autoclose_popups:{t:0,b:{t:2,i:[{t:3}],s:"自动关闭弹窗"}}}},kiosk:{loading:{t:0,b:{t:2,i:[{t:3}],s:"正在检查屏幕…"}},intro:{t:0,b:{t:2,i:[{t:3}],s:"把 FilaMind Flow 本身以全屏浏览器形式显示在触摸屏上——完全掌控屏幕显示内容。它与 KlipperScreen 互换：启动一个会停止另一个。"}},current:{t:0,b:{t:2,i:[{t:3}],s:"当前屏幕"}},mode:{kiosk:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind 自助屏"}},klipperscreen:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen"}},none:{t:0,b:{t:2,i:[{t:3}],s:"均未运行"}}},notInstalled:{t:0,b:{t:2,i:[{t:3}],s:"自助屏尚未安装"}},setupHint:{t:0,b:{t:2,i:[{t:3}],s:"在打印机主机上执行一次（安装全屏浏览器 + 自助屏服务）："}},persist:{t:0,b:{t:2,i:[{t:3}],s:"设为开机默认（否则切换是临时的——重启会恢复另一个）。"}},safety:{t:0,b:{t:2,i:[{t:3}],s:"默认临时：重启会恢复另一个。若屏幕变黑，通过 SSH 运行：sudo systemctl start KlipperScreen"}},switchBtn:{t:0,b:{t:2,i:[{t:3}],s:"切换到 FilaMind"}},restoreBtn:{t:0,b:{t:2,i:[{t:3}],s:"恢复 KlipperScreen"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"刷新"}},confirmSwitchTitle:{t:0,b:{t:2,i:[{t:3}],s:"把 FilaMind 显示到屏幕上？"}},confirmRestoreTitle:{t:0,b:{t:2,i:[{t:3}],s:"恢复 KlipperScreen？"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"这会停止一个屏幕服务并启动另一个。不影响正在进行的打印，但切换时触摸屏会黑屏几秒。"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"执行"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"取消"}},switchedNote:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind 正在接管屏幕——稍后即会出现。"}},restoredNote:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen 正在恢复——屏幕稍后返回。"}}},menus:{loading:{t:0,b:{t:2,i:[{t:3}],s:"正在加载菜单…"}},intro:{t:0,b:{t:2,i:[{t:3}],s:"设计触摸屏显示的内容：每个菜单的按钮、顺序及其作用。主屏网格是 __main 树，打印屏是 __print。"}},addItem:{t:0,b:{t:2,i:[{t:3}],s:"添加按钮"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"暂无项目——添加一个。"}},up:{t:0,b:{t:2,i:[{t:3}],s:"上移"}},down:{t:0,b:{t:2,i:[{t:3}],s:"下移"}},addChild:{t:0,b:{t:2,i:[{t:3}],s:"添加子项"}},delete:{t:0,b:{t:2,i:[{t:3}],s:"删除"}},name:{t:0,b:{t:2,i:[{t:3}],s:"名称"}},icon:{t:0,b:{t:2,i:[{t:3}],s:"图标"}},action:{t:0,b:{t:2,i:[{t:3}],s:"动作"}},actSubmenu:{t:0,b:{t:2,i:[{t:3}],s:"打开子菜单"}},actPanel:{t:0,b:{t:2,i:[{t:3}],s:"打开屏幕"}},actGcode:{t:0,b:{t:2,i:[{t:3}],s:"运行 G-code"}},panel:{t:0,b:{t:2,i:[{t:3}],s:"屏幕"}},gcode:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},enable:{t:0,b:{t:2,i:[{t:3}],s:"显示条件"}},save:{t:0,b:{t:2,i:[{t:3}],s:"保存菜单"}},newItem:{t:0,b:{t:2,i:[{t:3}],s:"新按钮"}},savedRestart:{t:0,b:{t:2,i:[{t:3}],s:"菜单已保存——重启 KlipperScreen 以查看。"}}},themes:{loading:{t:0,b:{t:2,i:[{t:3}],s:"正在加载主题…"}},palette:{t:0,b:{t:2,i:[{t:3}],s:"调色板"}},radius:{t:0,b:{t:2,i:[{t:3}],s:"圆角半径"}},preview:{t:0,b:{t:2,i:[{t:3}],s:"实时预览"}},btn:{t:0,b:{t:2,i:[{t:3}],s:"按钮"}},previewWarn:{t:0,b:{t:2,i:[{t:3}],s:"警告"}},previewApprox:{t:0,b:{t:2,i:[{t:3}],s:"近似预览——实际屏幕由 GTK 渲染，可能略有差异。"}},namePlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"新主题名称"}},createApply:{t:0,b:{t:2,i:[{t:3}],s:"创建并应用"}},createOnly:{t:0,b:{t:2,i:[{t:3}],s:"仅创建"}},installed:{t:0,b:{t:2,i:[{t:3}],s:"已安装主题"}},apply:{t:0,b:{t:2,i:[{t:3}],s:"应用"}},delete:{t:0,b:{t:2,i:[{t:3}],s:"删除主题"}},generated:{t:0,b:{t:2,i:[{t:3}],s:"本工具创建"}},created:{t:0,b:{t:2,i:[{t:3}],s:"主题已创建。从列表中应用，然后重启。"}},appliedRestart:{t:0,b:{t:2,i:[{t:3}],s:"已设置主题——重启 KlipperScreen 以查看。"}}},restart:{button:{t:0,b:{t:2,i:[{t:3}],s:"重启 KlipperScreen"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"重启中…"}},done:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen 正在重启——屏幕稍后会刷新。"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"重启 KlipperScreen？"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"这会重启触摸屏服务以应用更改。不会影响正在进行的打印，但屏幕会黑屏几秒。"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"重启"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"取消"}}}}};export{t as default};
